public void mapEntityToDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    next mapEntityToDataSource(_entityCtx, _dataSourceCtx);

    if(ETGACFParameters::find().EnableDMSIntegration == NoYes::Yes)
    {
        if (_entityCtx.getDatabaseOperation() == DataEntityDatabaseOperation::Insert || DataEntityDatabaseOperation::Update)
        {
            switch (_dataSourceCtx.name())
            {
                case dataEntityDataSourceStr(InventWarehouseEntity, InventLocation):
                    InventLocation inventLocation = _dataSourceCtx.getBuffer();
                    InventSiteId siteId = inventLocation.InventSiteId;


                    if (!InventSite::find(siteId, false).RecId)
                    {

                        InventSite newSite;
                        newSite.SiteId = siteId;
                        newSite.Name = siteId;
                        newSite.insert();

                    }
                    break;
            }
        }
    }
}
